bool Utilisateur::validateJsonForCreation(const Json::Value &pJson, std::string &err)
{
    if(pJson.isMember("id_user"))
    {
        if(!validJsonOfField(0, "id_user", pJson["id_user"], err, true))
            return false;
    }
    if(pJson.isMember("nom_user"))
    {
        if(!validJsonOfField(1, "nom_user", pJson["nom_user"], err, true))
            return false;
    }
    else
    {
        err="The nom_user column cannot be null";
        return false;
    }
    if(pJson.isMember("prenom_user"))
    {
        if(!validJsonOfField(2, "prenom_user", pJson["prenom_user"], err, true))
            return false;
    }
    else
    {
        err="The prenom_user column cannot be null";
        return false;
    }
    if(pJson.isMember("login_user"))
    {
        if(!validJsonOfField(3, "login_user", pJson["login_user"], err, true))
            return false;
    }
    else
    {
        err="The login_user column cannot be null";
        return false;
    }
    if(pJson.isMember("hash_mdp"))
    {
        if(!validJsonOfField(4, "hash_mdp", pJson["hash_mdp"], err, true))
            return false;
    }
    else
    {
        err="The hash_mdp column cannot be null";
        return false;
    }
    if(pJson.isMember("id_classe"))
    {
        if(!validJsonOfField(5, "id_classe", pJson["id_classe"], err, true))
            return false;
    }
    if(pJson.isMember("role_user"))
    {
        if(!validJsonOfField(6, "role_user", pJson["role_user"], err, true))
            return false;
    }
    else
    {
        err="The role_user column cannot be null";
        return false;
    }
    if(pJson.isMember("uuid_badge"))
    {
        if(!validJsonOfField(7, "uuid_badge", pJson["uuid_badge"], err, true))
            return false;
    }
    return true;
}
